    // Condition variables
    cond_id_t read_cv;   // wait for a complete line
    cond_id_t write_cv;  // wait for write to complete
    cond_id_t write_queue_cv; // wait for serialization of concurrent writes

    // Write serialization
    int write_in_progress; // is a write in progress?

