#include <threads.h>
#include <hardware.h>
#include <terminals.h>

/*
 * COMP 421 Lab 1 - MonTTY Terminal Device Driver
 *
 * Mesa-style monitor implementation.
 * One monitor for all terminals (NUM_TERMINALS).
 *
 * All 7 entry procedures call Declare_Monitor_Entry_Procedure() first.
 * Internal procedures are declared static.
 */

#define ERROR (-1)

/* Echo buffer per terminal: max 3 echo chars per keypress,
 * extra headroom for fast typists. */
#define ECHO_BUF_SIZE 1024

/* Fallback if TERMINAL_MAX_LINE not in headers */
#ifndef TERMINAL_MAX_LINE
#define TERMINAL_MAX_LINE 256
#endif

/* ------------------------------------------------------------------ */
/* Per-terminal state                                                   */
/* ------------------------------------------------------------------ */

typedef struct {
    /* --- Input buffer (circular, holds unread chars from keyboard) --- */
    char     inbuf[TERMINAL_MAX_LINE];
    int      inbuf_head;   /* next char to give to ReadTerminal */
    int      inbuf_tail;   /* next empty slot for incoming char */
    int      inbuf_count;  /* total chars currently in buffer   */
    int      inbuf_lines;  /* number of '\n' chars in buffer    */

    /* --- Echo queue (circular, chars to echo back to screen) --- */
    char     echobuf[ECHO_BUF_SIZE];
    int      echo_head;
    int      echo_tail;
    int      echo_count;

    /* --- Write state (for the current WriteTerminal call) --- */
    const char *write_buf;        /* caller's buffer            */
    int         write_len;        /* caller's buflen            */
    int         write_pos;        /* next char index to send    */
    int         write_pending;    /* 1: pending_char not yet tx */
    char        write_pending_char;
    int         write_in_progress; /* 1: a WriteTerminal is active */

    /* --- Transmitter state --- */
    int  tx_busy;   /* 1: hardware is currently transmitting */

    /* --- Condition variables --- */
    cond_id_t read_cv;       /* signal: complete line available */
    cond_id_t write_cv;      /* signal: current write completed  */
    cond_id_t write_lock_cv; /* signal: write slot became free   */

    /* --- Statistics --- */
    struct termstat stats;

    /* --- Initialization flag --- */
    int initialized;
} terminal_t;

static terminal_t terminals[NUM_TERMINALS];
static int driver_initialized = 0;

/* ================================================================== */
/* Internal (static) helper procedures                                  */
/* ================================================================== */

static void enqueue_echo(int term, char c)
{
    terminal_t *t = &terminals[term];
    if (t->echo_count < ECHO_BUF_SIZE) {
        t->echobuf[t->echo_tail] = c;
        t->echo_tail = (t->echo_tail + 1) % ECHO_BUF_SIZE;
        t->echo_count++;
    }
    /* If echo buffer full, silently drop (rare edge case). */
}

/*
 * try_transmit -- send the next character if the transmitter is idle.
 * Priority: echo queue > current WriteTerminal output.
 * Called from TransmitInterrupt (tx_busy was just cleared) and from
 * ReceiveInterrupt / WriteTerminal when tx_busy == 0.
 * Must be called only from within the monitor (no Declare_ here).
 */
static void try_transmit(int term)
{
    terminal_t *t = &terminals[term];

    /* Priority 1: echo queue */
    if (t->echo_count > 0) {
        char c = t->echobuf[t->echo_head];
        t->echo_head = (t->echo_head + 1) % ECHO_BUF_SIZE;
        t->echo_count--;
        WriteDataRegister(term, c);
        t->tx_busy = 1;
        t->stats.tty_out++;
        return;
    }

    /* Priority 2: pending extra char from \n -> \r\n expansion */
    if (t->write_in_progress && t->write_pending) {
        WriteDataRegister(term, t->write_pending_char);
        t->write_pending = 0;
        t->tx_busy = 1;
        t->stats.tty_out++;
        /* If that was the last char, wake the writer on next interrupt. */
        return;
    }

    /* Priority 3: next char from WriteTerminal buffer */
    if (t->write_in_progress && t->write_pos < t->write_len) {
        char c = t->write_buf[t->write_pos++];
        if (c == '\n') {
            /* Expand \n to \r\n */
            WriteDataRegister(term, '\r');
            t->write_pending = 1;
            t->write_pending_char = '\n';
        } else {
            WriteDataRegister(term, c);
        }
        t->tx_busy = 1;
        t->stats.tty_out++;
        return;
    }

    /*
     * Nothing left to transmit.  If a write was in progress and all
     * chars have been sent (and no pending expansion), wake the writer.
     */
    if (t->write_in_progress &&
        t->write_pos >= t->write_len &&
        !t->write_pending) {
        CondSignal(t->write_cv);
    }
    /* tx_busy stays 0 */
}

/* ================================================================== */
/* Entry procedures (Section 6.1 and 6.2)                              */
/* ================================================================== */

/* --- InitTerminalDriver ------------------------------------------- */

int
InitTerminalDriver(void)
{
    Declare_Monitor_Entry_Procedure();

    int i;

    if (driver_initialized)
        return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++) {
        terminal_t *t = &terminals[i];

        /* Input buffer */
        t->inbuf_head  = 0;
        t->inbuf_tail  = 0;
        t->inbuf_count = 0;
        t->inbuf_lines = 0;

        /* Echo queue */
        t->echo_head  = 0;
        t->echo_tail  = 0;
        t->echo_count = 0;

        /* Write state */
        t->write_buf        = 0;
        t->write_len        = 0;
        t->write_pos        = 0;
        t->write_pending    = 0;
        t->write_in_progress = 0;

        /* Transmitter */
        t->tx_busy = 0;

        /* Condition variables */
        t->read_cv       = CondCreate();
        t->write_cv      = CondCreate();
        t->write_lock_cv = CondCreate();

        /* Stats: -1 until InitTerminal called */
        t->stats.tty_in  = -1;
        t->stats.tty_out = -1;
        t->stats.user_in  = -1;
        t->stats.user_out = -1;

        t->initialized = 0;
    }

    driver_initialized = 1;
    return 0;
}

/* --- InitTerminal -------------------------------------------------- */

int
InitTerminal(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (terminals[term].initialized)
        return ERROR;

    if (InitHardware(term) != 0)
        return ERROR;

    terminals[term].stats.tty_in  = 0;
    terminals[term].stats.tty_out = 0;
    terminals[term].stats.user_in  = 0;
    terminals[term].stats.user_out = 0;
    terminals[term].initialized = 1;

    return 0;
}

/* --- TerminalDriverStatistics ------------------------------------- */

int
TerminalDriverStatistics(struct termstat *stats)
{
    Declare_Monitor_Entry_Procedure();
    int i;

    if (!driver_initialized)
        return ERROR;
    if (stats == 0)
        return ERROR;

    for (i = 0; i < NUM_TERMINALS; i++) {
        stats[i] = terminals[i].stats;
    }
    return 0;
}

/* --- WriteTerminal ------------------------------------------------- */

int
WriteTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();
    terminal_t *t;

    if (!driver_initialized)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (!terminals[term].initialized)
        return ERROR;
    if (buf == 0)
        return ERROR;
    if (buflen < 0)
        return ERROR;
    if (buflen == 0)
        return 0;

    t = &terminals[term];
    t->stats.user_in += buflen;

    /* Serialize: wait until no other WriteTerminal is active */
    while (t->write_in_progress)
        CondWait(t->write_lock_cv);

    /* Claim the write slot */
    t->write_buf        = buf;
    t->write_len        = buflen;
    t->write_pos        = 0;
    t->write_pending    = 0;
    t->write_in_progress = 1;

    /* Kick off transmission if the transmitter is idle */
    if (!t->tx_busy)
        try_transmit(term);

    /* Wait until all chars have been transmitted */
    while (t->write_pos < t->write_len || t->write_pending)
        CondWait(t->write_cv);

    /* Release write slot and wake next waiter */
    t->write_in_progress = 0;
    CondSignal(t->write_lock_cv);

    return buflen;
}

/* --- ReadTerminal -------------------------------------------------- */

int
ReadTerminal(int term, char *buf, int buflen)
{
    Declare_Monitor_Entry_Procedure();
    terminal_t *t;
    int count;

    if (!driver_initialized)
        return ERROR;
    if (term < 0 || term >= NUM_TERMINALS)
        return ERROR;
    if (!terminals[term].initialized)
        return ERROR;
    if (buf == 0)
        return ERROR;
    if (buflen < 0)
        return ERROR;
    if (buflen == 0)
        return 0;

    t = &terminals[term];

    /* Block until at least one complete line is available */
    while (t->inbuf_lines == 0)
        CondWait(t->read_cv);

    /* Read up to buflen chars, stopping after the first '\n' */
    count = 0;
    while (count < buflen) {
        char c = t->inbuf[t->inbuf_head];
        t->inbuf_head  = (t->inbuf_head + 1) % TERMINAL_MAX_LINE;
        t->inbuf_count--;
        buf[count++] = c;
        if (c == '\n') {
            t->inbuf_lines--;
            break;
        }
    }

    /* If more complete lines remain, wake another ReadTerminal waiter */
    if (t->inbuf_lines > 0)
        CondSignal(t->read_cv);

    t->stats.user_out += count;
    return count;
}

/* --- ReceiveInterrupt (bottom half) -------------------------------- */

void
ReceiveInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();
    /* MUST NOT call CondWait in this handler. */

    terminal_t *t;
    char c;

    if (!driver_initialized || term < 0 || term >= NUM_TERMINALS)
        return;
    t = &terminals[term];
    if (!t->initialized)
        return;

    c = ReadDataRegister(term);
    t->stats.tty_in++;

    if (c == '\r' || c == '\n') {
        /* Store '\n' in input buffer, echo "\r\n" */
        if (t->inbuf_count < TERMINAL_MAX_LINE) {
            t->inbuf[t->inbuf_tail] = '\n';
            t->inbuf_tail  = (t->inbuf_tail + 1) % TERMINAL_MAX_LINE;
            t->inbuf_count++;
            t->inbuf_lines++;
            CondSignal(t->read_cv);
        }
        enqueue_echo(term, '\r');
        enqueue_echo(term, '\n');

    } else if (c == '\b' || c == '\177') {
        /* Backspace/delete: remove last char only if not a completed line */
        int last_idx = (t->inbuf_tail - 1 + TERMINAL_MAX_LINE) % TERMINAL_MAX_LINE;
        if (t->inbuf_count > 0 && t->inbuf[last_idx] != '\n') {
            t->inbuf_tail   = last_idx;
            t->inbuf_count--;
            enqueue_echo(term, '\b');
            enqueue_echo(term, ' ');
            enqueue_echo(term, '\b');
        }
        /* If buffer empty or last char is '\n', ignore the backspace */

    } else {
        /* Regular printable character */
        if (t->inbuf_count < TERMINAL_MAX_LINE) {
            t->inbuf[t->inbuf_tail] = c;
            t->inbuf_tail  = (t->inbuf_tail + 1) % TERMINAL_MAX_LINE;
            t->inbuf_count++;
            enqueue_echo(term, c);
        }
        /* Buffer full: drop char (could optionally echo '\a' bell) */
    }

    /* Start transmitting if the hardware is idle */
    if (!t->tx_busy)
        try_transmit(term);
}

/* --- TransmitInterrupt (bottom half) ------------------------------ */

void
TransmitInterrupt(int term)
{
    Declare_Monitor_Entry_Procedure();

    if (!driver_initialized || term < 0 || term >= NUM_TERMINALS)
        return;

    terminals[term].tx_busy = 0;
    try_transmit(term);
}
